sys_script_include.script:
/**
 * PubCrawlQRGenerator
 * Generates QR code URLs for venue check-ins
 */
var PubCrawlQRGenerator = Class.create();

PubCrawlQRGenerator.prototype = {
    initialize: function() {},

    /**
     * Generates a check-in URL for QR code scanning
     * @param {string} venueSysId - The sys_id of the venue
     * @returns {string} URL encoding the venue sys_id for QR scanning
     */
    generateCheckinURL: function(venueSysId) {
        var instanceName = gs.getProperty('instance_name');
        var baseURL = 'https://' + instanceName + '.service-now.com';
        var checkinPath = '/api/x_1838075_pub_cr_0/checkin';
        var url = baseURL + checkinPath + '?venue=' + encodeURIComponent(venueSysId);
        return url;
    },

    type: 'PubCrawlQRGenerator'
};
